import json, os, re
# load citing records from previous query
data_var = var_call_oaA8mmohN4pCeH030bqtJaIj
# data_var may be a path (string) or a list
if isinstance(data_var, str) and os.path.exists(data_var):
    with open(data_var, 'r', encoding='utf-8') as f:
        records = json.load(f)
else:
    records = data_var

results = []
primary_codes = []
for rec in records:
    rowid = rec.get('rowid')
    pi = rec.get('Patents_info','')
    # try to extract assignee from Patents_info; common formats: 'is assigned to X' or 'is owned by X' or 'is assigned to X and has publication number'
    assignee = None
    m = re.search(r'is assigned to\s+([^\.\,\n]+)', pi, flags=re.IGNORECASE)
    if not m:
        m = re.search(r'is owned by\s+([^\.\,\n]+)', pi, flags=re.IGNORECASE)
    if not m:
        m = re.search(r'holds the .* filing .* with pub\. number .*? and is assigned to\s+([^\.\,\n]+)', pi, flags=re.IGNORECASE)
    if m:
        assignee = m.group(1).strip()
    else:
        # fallback: look for pattern 'assigned to XYZ' anywhere
        m2 = re.search(r'assigned to\s+([^\.\,\n]+)', pi, flags=re.IGNORECASE)
        if m2:
            assignee = m2.group(1).strip()
    if not assignee:
        # fallback: try to find uppercase organization words
        m3 = re.search(r'([A-Z][A-Z\s\.&-]{3,}?)\s+(and has|with pub|has publication|has pub|holds the|holds)', pi)
        if m3:
            assignee = m3.group(1).strip()
    if not assignee:
        assignee = ''
    # parse cpc field (string)
    cpc_field = rec.get('cpc','')
    cpc_list = []
    try:
        cpc_list = json.loads(cpc_field)
    except Exception:
        # maybe already a list
        if isinstance(cpc_field, list):
            cpc_list = cpc_field
    primary = None
    for item in cpc_list:
        if isinstance(item, dict) and item.get('first'):
            primary = item.get('code')
            break
    if not primary and cpc_list:
        # take first code if none marked first
        if isinstance(cpc_list[0], dict):
            primary = cpc_list[0].get('code')
    if primary and primary not in primary_codes:
        primary_codes.append(primary)
    results.append({'rowid': rowid, 'assignee': assignee, 'primary_cpc': primary})

# dedupe assignees excluding Univ California
final = []
for r in results:
    a = r['assignee'].upper()
    if 'UNIV' in a and 'CALIFORNIA' in a:
        continue
    if a.strip() == '':
        continue
    final.append({'rowid': r['rowid'], 'assignee': r['assignee'], 'primary_cpc': r['primary_cpc']})
# unique by assignee and primary code
unique = {}
for r in final:
    key = r['assignee'].strip()
    if key not in unique:
        unique[key] = set()
    if r['primary_cpc']:
        unique[key].add(r['primary_cpc'])
# prepare list of unique primary codes to query definitions
codes = sorted({c for s in unique.values() for c in s if c})
output = {'assignee_to_codes': {k: sorted(list(v)) for k,v in unique.items()}, 'codes_to_query': codes}
print('__RESULT__:')
print(json.dumps(output))

